 1	import * as React from 'react';
 2	
 3	import {
 4	  DashboardsOverviewPrometheusActivity,
 5	  DashboardsOverviewResourceActivity,
 6	  DashboardsOverviewResourceActivity as DynamicDashboardsOverviewResourceActivity,
 7	  isDashboardsOverviewPrometheusActivity as isDynamicDashboardsOverviewPrometheusActivity,
 8	  isDashboardsOverviewResourceActivity as isDynamicDashboardsOverviewResourceActivity,
 9	  useK8sModels,
10	  useResolvedExtensions,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import {
13	  LoadedExtension,
14	  ResolvedExtension,
15	} from '@openshift-console/dynamic-plugin-sdk/lib/types';
16	
17	const useDashboardActivities = () => {
18	  const [models] = useK8sModels();
19	
20	  const [dynamicResourceActivityExtensions] =
21	    useResolvedExtensions<DynamicDashboardsOverviewResourceActivity>(
22	      isDynamicDashboardsOverviewResourceActivity,
23	    );
24	
25	  const resourceActivities: (
26	    | LoadedExtension<DashboardsOverviewResourceActivity>
27	    | ResolvedExtension<DynamicDashboardsOverviewResourceActivity>
28	  )[] = React.useMemo(
29	    () =>
30	      dynamicResourceActivityExtensions?.filter((e) => !!models?.[e.properties.k8sResource.kind]),
31	    [dynamicResourceActivityExtensions, models],
32	  );
33	
34	  const [dynamicPrometheusActivities] = useResolvedExtensions<DashboardsOverviewPrometheusActivity>(
35	    isDynamicDashboardsOverviewPrometheusActivity,
36	  );
37	
38	  return {
39	    prometheusActivities: dynamicPrometheusActivities,
40	    resourceActivities,
41	  };
42	};
43	
44	export default useDashboardActivities;

